import type { LoiData } from './types';

const escapeHtml = (value: string): string =>
  value.replace(/[&<>"']/g, (character) => {
    const entities: Record<string, string> = {
      '&': '&amp;',
      '<': '&lt;',
      '>': '&gt;',
      '"': '&quot;',
      "'": '&#039;',
    };
    return entities[character] ?? character;
  });

export const openPrintCopy = (data: LoiData, reference: string, logoUrl: string): boolean => {
  const printWindow = window.open('', '_blank');
  if (!printWindow) return false;
  printWindow.opener = null;
  const row = (label: string, value: string): string =>
    `<div><dt>${escapeHtml(label)}</dt><dd>${escapeHtml(value || 'Not provided')}</dd></div>`;
  const submittedDate = new Date(`${data.signatureDate}T12:00:00`).toLocaleDateString('en-US', {
    year: 'numeric',
    month: 'long',
    day: 'numeric',
  });

  printWindow.document.open();
  printWindow.document.write(`<!doctype html><html><head><title>${escapeHtml(reference)} — SwiftAid LOI</title>
    <style>
      body{color:#14283e;font:14px Arial,sans-serif;margin:0;padding:36px}header{align-items:center;border-bottom:4px solid #009fa6;display:flex;justify-content:space-between;padding-bottom:20px}header img{height:92px;width:220px;object-fit:contain}h1{color:#0b3158;font-size:24px;margin:0;text-align:right}header span{color:#5c6d7f;display:block;font-size:12px;margin-top:5px}dl{display:grid;grid-template-columns:1fr 1fr;margin:28px 0}dl div{border-bottom:1px solid #d8e4ea;padding:12px}dt{color:#5c6d7f;font-size:10px;font-weight:700;letter-spacing:.08em;text-transform:uppercase}dd{font-weight:600;margin:5px 0 0}.legal{background:#eff8fc;border-left:4px solid #009fa6;line-height:1.55;padding:18px}.signature{display:grid;gap:24px;grid-template-columns:1.4fr 1fr 1fr;margin-top:44px}.signature div{border-top:1px solid #14283e;padding-top:8px}.signature span{color:#5c6d7f;display:block;font-size:10px;text-transform:uppercase}footer{color:#5c6d7f;font-size:10px;margin-top:58px;text-align:center}@media print{body{padding:18px}}
    </style></head><body><header><img src="${escapeHtml(logoUrl)}" alt="SwiftAid Transport"><div><h1>Healthcare Facility Letter of Intent</h1><span>Nonbinding planning document</span></div></header>
    <dl>
      ${row('Reference', reference)}
      ${row('Facility', data.facilityName)}
      ${row('Facility type', data.facilityType)}
      ${row('Address', `${data.address}, ${data.city}, ${data.state} ${data.zip}`)}
      ${row('Primary contact', `${data.contactName}, ${data.title}`)}
      ${row('Email / phone', `${data.email} · ${data.phone}`)}
      ${row('Estimated weekly trips', data.weeklyTrips)}
      ${row('Anticipated timing', data.launchTiming)}
      ${row('Payment approach', data.paymentApproach)}
      ${row('Trip needs', data.tripNeeds.join(', '))}
      ${row('Future interest', data.futureServices.join(', ') || 'None selected')}
    </dl>
    <div class="legal"><strong>Nonbinding statement</strong><p>The facility expresses a good-faith interest in exploring a future transportation relationship with SwiftAid Transport LLC. This document supports demand validation and operational planning only. It is not a contract, pricing agreement, vendor approval, referral guarantee, or obligation for either party to proceed.</p></div>
    <div class="signature"><div><span>Authorized signer</span><strong>${escapeHtml(data.signerName)}</strong></div><div><span>Title</span><strong>${escapeHtml(data.signerTitle)}</strong></div><div><span>Date</span><strong>${escapeHtml(submittedDate)}</strong></div></div>
    <footer>SwiftAid Transport LLC · Orange County, New York · 973-315-6000 · contact@swiftaidtransport.com</footer>
    <script>window.addEventListener('load',()=>setTimeout(()=>window.print(),250));</script></body></html>`);
  printWindow.document.close();
  return true;
};
