import React, { type FC, type FormEvent, useEffect, useRef, useState } from 'react';
import { submissions } from '@wix/forms';
import { AuthorizationStep, ContactStep, FacilityStep, NeedsStep } from './form-steps';
import { openPrintCopy } from './print-copy';
import styles from './element.module.css';
import { initialData, type LoiData, type SubmissionStatus } from './types';

const stepLabel = (step: number): string => {
  switch (step) {
    case 1: return 'Facility';
    case 2: return 'Contact';
    case 3: return 'Transportation needs';
    case 4: return 'Authorization';
    default: return 'Facility';
  }
};

const LoiForm: FC<{ logoUrl: string }> = ({ logoUrl }) => {
  const returnedParams = typeof window === 'undefined' ? null : new URLSearchParams(window.location.search);
  const returnedSuccess = returnedParams?.get('loi') === 'submitted';
  const returnedReference = returnedParams?.get('ref') || '';
  const [data, setData] = useState<LoiData>(() => {
    if (!returnedSuccess || typeof window === 'undefined') return initialData();
    try {
      const saved = window.sessionStorage.getItem('swiftaid-loi-submission');
      if (!saved) return initialData();
      const parsed = JSON.parse(saved) as { data?: LoiData };
      return parsed.data || initialData();
    } catch {
      return initialData();
    }
  });
  const [step, setStep] = useState(1);
  const [status, setStatus] = useState<SubmissionStatus>(returnedSuccess ? 'success' : 'idle');
  const [errorMessage, setErrorMessage] = useState('');
  const [reference] = useState(returnedReference || `SAT-LOI-${Date.now().toString(36).toUpperCase()}`);
  const confirmationRef = useRef<HTMLElement>(null);

  useEffect(() => {
    if (status === 'success') confirmationRef.current?.scrollIntoView({ behavior: 'smooth', block: 'center' });
  }, [status]);

  const update = <K extends keyof LoiData>(name: K, value: LoiData[K]): void => {
    setData((current) => ({ ...current, [name]: value }));
  };

  const toggleList = (name: 'tripNeeds' | 'futureServices', value: string): void => {
    setData((current) => ({
      ...current,
      [name]: current[name].includes(value)
        ? current[name].filter((item) => item !== value)
        : [...current[name], value],
    }));
  };

  const validateStep = (): boolean => {
    let complete = true;
    if (step === 1) complete = Boolean(data.facilityName && data.facilityType && data.address && data.city && data.state && data.zip);
    if (step === 2) {
      complete = Boolean(data.contactName && data.title && data.email && data.phone);
      if (complete && !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(data.email)) {
        setErrorMessage('Please enter a valid work email address.');
        return false;
      }
    }
    if (step === 3) complete = Boolean(data.weeklyTrips && data.launchTiming && data.paymentApproach);
    if (step === 4) complete = Boolean(data.signerName && data.signerTitle && data.signatureDate);
    if (!complete) {
      setErrorMessage('Please complete every required field before continuing.');
      return false;
    }
    if (step === 3 && data.tripNeeds.length === 0) {
      setErrorMessage('Select at least one anticipated transportation need.');
      return false;
    }
    if (step === 4 && (!data.authorization || !data.nonbinding || !data.noPhi)) {
      setErrorMessage('Please confirm all three acknowledgments before submitting.');
      return false;
    }
    setErrorMessage('');
    return true;
  };

  const nextStep = (): void => {
    if (!validateStep()) return;
    setStep((current) => Math.min(4, current + 1));
  };

  const submitLoi = async (event: FormEvent<HTMLFormElement>): Promise<void> => {
    event.preventDefault();
    if (step < 4) {
      nextStep();
      return;
    }
    if (!validateStep() || data.honey) {
      return;
    }
    setStatus('sending');
    setErrorMessage('');
    try {
      window.sessionStorage.setItem('swiftaid-loi-submission', JSON.stringify({ data, reference }));
    } catch (error) {
      console.warn('SwiftAid could not preserve the printable LOI copy:', error);
    }

    const nameParts = data.contactName.trim().split(/\s+/);
    const firstName = nameParts.shift() || 'Facility';
    const lastName = nameParts.join(' ') || 'Authorized Contact';
    const facilityTypeMap: Record<string, string> = {
      'Hospital or health system': 'Hospital / discharge team',
      'Medical practice or clinic': 'Clinic / medical office',
      'Dialysis center': 'Dialysis center',
      'Rehabilitation facility': 'Rehabilitation center',
      'Senior living community': 'Assisted living community',
      'Skilled nursing facility': 'Nursing home',
    };
    const facilityType = facilityTypeMap[data.facilityType] || 'Other';
    const facilityLocation = [
      data.address,
      `${data.city}, ${data.state} ${data.zip}`,
      data.website ? `Website: ${data.website}` : '',
    ].filter(Boolean).join(' — ');
    const transportationSupport = [
      `Trip needs: ${data.tripNeeds.join(', ')}`,
      `Payment approach: ${data.paymentApproach}`,
      `Need timing: ${data.launchTiming}`,
    ].join(' | ');
    const additionalNotes = [
      `LOI reference: ${reference}`,
      `Future service interest: ${data.futureServices.join(', ') || 'None selected'}`,
      `Operational notes (no PHI): ${data.notes || 'None provided'}`,
      `Authorized signer: ${data.signerName}, ${data.signerTitle}`,
      `Signature date: ${data.signatureDate}`,
      'Authorization, nonbinding status, and no-PHI acknowledgments: Confirmed',
    ].join('\n');

    try {
      await submissions.createSubmission({
        formId: '0666cc64-7fdb-4944-b6d4-44d2d2988860',
        seen: false,
        submissions: {
          first_name_facility_0001: firstName,
          last_name_facility_0002: lastName,
          email_facility_0003: data.email,
          phone_facility_0004: data.phone,
          job_title_facility_0005: data.title,
          facility_name_0006: data.facilityName,
          facility_type_0007: facilityType,
          facility_location_0008: facilityLocation,
          transportation_support_0009: transportationSupport,
          approx_volume_0010: `${data.weeklyTrips} one-way trips per week`,
          loi_interest_0011: 'Yes, send a Partnership Interest Letter',
          best_time_to_contact_0012: data.launchTiming,
          additional_notes_0013: additionalNotes,
        },
      });
      setStatus('success');
    } catch (error) {
      console.error('SwiftAid LOI submission failed:', error);
      setStatus('error');
      setErrorMessage('We could not transmit the LOI. Please try again or call SwiftAid at 973-315-6000.');
    }
  };

  if (status === 'success') {
    const firstName = data.contactName.trim().split(/\s+/)[0] || 'there';
    return (
      <section className={styles.confirmation} ref={confirmationRef} aria-live="polite">
        <div className={styles.successMark} aria-hidden="true">✓</div>
        <p className={styles.eyebrow}>Letter of Intent submitted</p>
        <h2>Thank you, {firstName}.</h2>
        <p>
          SwiftAid has received the nonbinding LOI from <strong>{data.facilityName}</strong>. A submission copy was
          requested for <strong>{data.email}</strong>.
        </p>
        <div className={styles.reference}><span>Reference</span><strong>{reference}</strong></div>
        <div className={styles.confirmationActions}>
          <button className={`${styles.button} ${styles.buttonPrimary}`} onClick={() => {
            if (!openPrintCopy(data, reference, logoUrl)) setErrorMessage('Allow pop-ups to open the PDF-ready copy.');
          }}>Download / Save PDF</button>
          <a className={`${styles.button} ${styles.buttonSecondary}`} href="mailto:contact@swiftaidtransport.com?subject=Facility%20LOI%20Follow-Up">Contact SwiftAid</a>
        </div>
        {errorMessage ? <p className={styles.formError} role="alert">{errorMessage}</p> : null}
      </section>
    );
  }

  const stepProps = { data, update, toggleList };
  return (
    <form
      className={styles.loiForm}
      onSubmit={submitLoi}
      noValidate
    >
      <div className={styles.formTopline}>
        <div><span>Step {step} of 4</span><strong>{stepLabel(step)}</strong></div>
        <span>{step * 25}% complete</span>
      </div>
      <div className={styles.progressTrack} aria-hidden="true"><span style={{ width: `${step * 25}%` }} /></div>
      <input className={styles.honey} tabIndex={-1} autoComplete="off" value={data.honey} onChange={(event) => update('honey', event.target.value)} />
      {step === 1 ? <FacilityStep {...stepProps} /> : null}
      {step === 2 ? <ContactStep {...stepProps} /> : null}
      {step === 3 ? <NeedsStep {...stepProps} /> : null}
      {step === 4 ? <AuthorizationStep {...stepProps} /> : null}
      {errorMessage ? <p className={styles.formError} role="alert">{errorMessage}</p> : null}
      <div className={styles.formActions}>
        {step > 1 ? (
          <button type="button" className={`${styles.button} ${styles.buttonSecondary}`} onClick={() => {
            setStep((current) => current - 1);
            setErrorMessage('');
          }}>← Back</button>
        ) : <span />}
        {step < 4 ? (
          <button type="button" className={`${styles.button} ${styles.buttonPrimary}`} onClick={nextStep}>Continue →</button>
        ) : (
          <button type="submit" className={`${styles.button} ${styles.buttonPrimary}`} disabled={status === 'sending'}>
            {status === 'sending' ? 'Sending LOI…' : 'Submit Nonbinding LOI →'}
          </button>
        )}
      </div>
      {status === 'error' ? <p className={styles.formHelp}>You may also email <a href="mailto:contact@swiftaidtransport.com">contact@swiftaidtransport.com</a>.</p> : null}
    </form>
  );
};

export default LoiForm;
