import React, { type FC } from 'react';
import { futureOptions, tripOptions } from './content';
import Field from './form-field';
import styles from './element.module.css';
import type { LoiData } from './types';

type StepProps = {
  data: LoiData;
  update: <K extends keyof LoiData>(name: K, value: LoiData[K]) => void;
  toggleList: (name: 'tripNeeds' | 'futureServices', value: string) => void;
};

export const FacilityStep: FC<StepProps> = ({ data, update }) => (
  <fieldset>
    <legend>Facility information</legend>
    <p className={styles.fieldIntro}>Tell us which organization is expressing interest.</p>
    <div className={styles.fieldGrid}>
      <Field label="Facility or organization name *" wide>
        <input value={data.facilityName} onChange={(event) => update('facilityName', event.target.value)} autoComplete="organization" />
      </Field>
      <Field label="Facility type *">
        <select value={data.facilityType} onChange={(event) => update('facilityType', event.target.value)}>
          <option value="">Select one</option>
          <option>Hospital or health system</option>
          <option>Medical practice or clinic</option>
          <option>Dialysis center</option>
          <option>Rehabilitation facility</option>
          <option>Behavioral health provider</option>
          <option>Senior living community</option>
          <option>Skilled nursing facility</option>
          <option>Community or social service organization</option>
          <option>Other healthcare-related organization</option>
        </select>
      </Field>
      <Field label="Website">
        <input type="url" value={data.website} onChange={(event) => update('website', event.target.value)} placeholder="https://" />
      </Field>
      <Field label="Street address *" wide>
        <input value={data.address} onChange={(event) => update('address', event.target.value)} autoComplete="street-address" />
      </Field>
      <Field label="City *">
        <input value={data.city} onChange={(event) => update('city', event.target.value)} autoComplete="address-level2" />
      </Field>
      <Field label="State *">
        <input value={data.state} onChange={(event) => update('state', event.target.value)} autoComplete="address-level1" />
      </Field>
      <Field label="ZIP code *">
        <input value={data.zip} onChange={(event) => update('zip', event.target.value)} inputMode="numeric" autoComplete="postal-code" />
      </Field>
    </div>
  </fieldset>
);

export const ContactStep: FC<StepProps> = ({ data, update }) => (
  <fieldset>
    <legend>Primary facility contact</legend>
    <p className={styles.fieldIntro}>Who should SwiftAid contact about partnership planning?</p>
    <div className={styles.fieldGrid}>
      <Field label="Full name *">
        <input value={data.contactName} onChange={(event) => update('contactName', event.target.value)} autoComplete="name" />
      </Field>
      <Field label="Professional title *">
        <input value={data.title} onChange={(event) => update('title', event.target.value)} autoComplete="organization-title" />
      </Field>
      <Field label="Work email *">
        <input type="email" value={data.email} onChange={(event) => update('email', event.target.value)} autoComplete="email" />
      </Field>
      <Field label="Direct phone *">
        <input type="tel" value={data.phone} onChange={(event) => update('phone', event.target.value)} autoComplete="tel" />
      </Field>
    </div>
  </fieldset>
);

export const NeedsStep: FC<StepProps> = ({ data, update, toggleList }) => (
  <fieldset>
    <legend>Anticipated transportation needs</legend>
    <p className={styles.fieldIntro}>Best estimates are welcome. These answers are for planning and are not commitments.</p>
    <div className={styles.fieldGrid}>
      <Field label="Estimated one-way trips per week *">
        <select value={data.weeklyTrips} onChange={(event) => update('weeklyTrips', event.target.value)}>
          <option value="">Select a range</option>
          <option>1–5</option><option>6–15</option><option>16–30</option><option>31–60</option><option>61+</option><option>Unknown — needs discussion</option>
        </select>
      </Field>
      <Field label="Anticipated need timing *">
        <select value={data.launchTiming} onChange={(event) => update('launchTiming', event.target.value)}>
          <option value="">Select one</option>
          <option>At SwiftAid’s Q1 2027 launch</option>
          <option>Within 3–6 months after launch</option>
          <option>Later in 2027</option>
          <option>Exploratory — timing unknown</option>
        </select>
      </Field>
      <Field label="Possible payment approach *" wide>
        <select value={data.paymentApproach} onChange={(event) => update('paymentApproach', event.target.value)}>
          <option value="">Select one</option>
          <option>Facility-paid transportation</option>
          <option>Patient or family private pay</option>
          <option>Combination of facility and private pay</option>
          <option>Needs discussion</option>
        </select>
      </Field>
    </div>
    <ChoiceGroup title="Anticipated trip needs *" options={tripOptions} selected={data.tripNeeds} onToggle={(value) => toggleList('tripNeeds', value)} />
    <ChoiceGroup title="Future service interest" options={futureOptions} selected={data.futureServices} onToggle={(value) => toggleList('futureServices', value)} />
    <Field label="Operational notes" hint="Do not include patient names, diagnoses, medical record numbers, appointment details, or other PHI." wide>
      <textarea value={data.notes} onChange={(event) => update('notes', event.target.value)} rows={4} placeholder="Share general scheduling or coordination considerations only." />
    </Field>
  </fieldset>
);

const ChoiceGroup: FC<{
  title: string;
  options: string[];
  selected: string[];
  onToggle: (value: string) => void;
}> = ({ title, options, selected, onToggle }) => (
  <div className={styles.choiceGroup}>
    <span>{title}</span>
    <div className={styles.choiceGrid}>
      {options.map((option) => (
        <label className={styles.choice} key={option}>
          <input type="checkbox" checked={selected.includes(option)} onChange={() => onToggle(option)} />
          <span>{option}</span>
        </label>
      ))}
    </div>
  </div>
);

export const AuthorizationStep: FC<StepProps> = ({ data, update }) => (
  <fieldset>
    <legend>Authorization and acknowledgment</legend>
    <div className={styles.legalCopy}>
      <strong>Nonbinding statement of intent</strong>
      <p>
        On behalf of the facility named in this form, the undersigned expresses a good-faith interest in exploring
        a future transportation relationship with SwiftAid Transport LLC. This LOI is for demand validation and
        operational planning only. It does not create a contract, guarantee service or pricing, establish
        exclusivity, approve SwiftAid as a vendor, require referrals, or obligate either party to proceed.
      </p>
    </div>
    <div className={styles.fieldGrid}>
      <Field label="Authorized signer’s full name *">
        <input value={data.signerName} onChange={(event) => update('signerName', event.target.value)} />
      </Field>
      <Field label="Signer’s title *">
        <input value={data.signerTitle} onChange={(event) => update('signerTitle', event.target.value)} />
      </Field>
      <Field label="Signature date *">
        <input type="date" value={data.signatureDate} onChange={(event) => update('signatureDate', event.target.value)} />
      </Field>
    </div>
    <div className={styles.acknowledgments}>
      <label><input type="checkbox" checked={data.authorization} onChange={(event) => update('authorization', event.target.checked)} /><span>I am authorized to express partnership interest on behalf of this facility.</span></label>
      <label><input type="checkbox" checked={data.nonbinding} onChange={(event) => update('nonbinding', event.target.checked)} /><span>I understand this LOI is nonbinding and is not a service or pricing agreement.</span></label>
      <label><input type="checkbox" checked={data.noPhi} onChange={(event) => update('noPhi', event.target.checked)} /><span>I confirm that no patient information or protected health information is included.</span></label>
    </div>
  </fieldset>
);
