import { createFilterFactory, createSortFactory } from './wql-builder-utils.js';
// ============ Search Params Builder ============
/**
 * Creates a SearchParamsBuilder for constructing search parameters
 * @returns A SearchParamsBuilder with chainable methods
 */
function createSearchParamsBuilder() {
    let state = {};
    const builder = {
        get search() {
            return state;
        },
        expression(expr) {
            state = { ...state, expression: expr };
            return builder;
        },
        mode(mode) {
            state = { ...state, mode };
            return builder;
        },
        fields(fields) {
            state = { ...state, fields };
            return builder;
        },
        fuzzy(enabled = true) {
            state = { ...state, fuzzy: enabled };
            return builder;
        },
    };
    return builder;
}
/**
 * Creates the Search params factory
 * @returns A SearchParamsFactory for creating search expressions
 */
function createSearchParamsFactory() {
    return (expression) => {
        const builder = createSearchParamsBuilder();
        if (expression !== undefined) {
            return builder.expression(expression);
        }
        return builder;
    };
}
// ============ Aggregation Builder ============
/**
 * Creates a ValueAggregationBuilder
 * @param baseAgg - Base aggregation to extend
 * @returns A ValueAggregationBuilder instance
 */
function createValueAggregationBuilder(baseAgg) {
    let state = {
        ...baseAgg,
        type: 'VALUE',
        value: { ...baseAgg.value },
    };
    const builder = {
        get aggregation() {
            return state;
        },
        sortBy(type, direction) {
            state = {
                ...state,
                value: { ...state.value, sortType: type, sortDirection: direction },
            };
            return builder;
        },
        limit(count) {
            state = { ...state, value: { ...state.value, limit: count } };
            return builder;
        },
        excludeMissingValues() {
            state = { ...state, value: { ...state.value, missingValues: 'EXCLUDE' } };
            return builder;
        },
        includeMissingValues() {
            state = { ...state, value: { ...state.value, missingValues: 'INCLUDE' } };
            return builder;
        },
        includeValues(addToBucket) {
            state = {
                ...state,
                value: { ...state.value, includeOptions: { addToBucket } },
            };
            return builder;
        },
    };
    return builder;
}
/**
 * Creates a RangeAggregationBuilder
 * @param baseAgg - Base aggregation to extend
 * @returns A RangeAggregationBuilder instance
 */
function createRangeAggregationBuilder(baseAgg) {
    let state = {
        ...baseAgg,
        type: 'RANGE',
        range: { buckets: [] },
    };
    const builder = {
        get aggregation() {
            return state;
        },
        withBuckets(...buckets) {
            state = { ...state, range: { buckets } };
            return builder;
        },
    };
    return builder;
}
/**
 * Creates a DateHistogramAggregationBuilder
 * @param baseAgg - Base aggregation to extend
 * @returns A DateHistogramAggregationBuilder instance
 */
function createDateHistogramAggregationBuilder(baseAgg) {
    let state = {
        ...baseAgg,
        type: 'DATE_HISTOGRAM',
        dateHistogram: {},
    };
    const builder = {
        get aggregation() {
            return state;
        },
        interval(interval) {
            state = { ...state, dateHistogram: { interval } };
            return builder;
        },
    };
    return builder;
}
/**
 * Creates a ScalarAggregationBuilder
 * @param baseAgg - Base aggregation to extend
 * @returns A ScalarAggregationBuilder instance
 */
function createScalarAggregationBuilder(baseAgg) {
    let state = { ...baseAgg, type: 'SCALAR', scalar: {} };
    const builder = {
        get aggregation() {
            return state;
        },
        type(scalarType) {
            state = { ...state, scalar: { type: scalarType } };
            return builder;
        },
    };
    return builder;
}
/**
 * Creates a NestedAggregationBuilder
 * @param baseAgg - Base aggregation to extend
 * @returns A NestedAggregationBuilder instance
 */
function createNestedAggregationBuilder(baseAgg) {
    let state = {
        ...baseAgg,
        type: 'NESTED',
        nested: { nestedAggregations: [] },
    };
    const builder = {
        get aggregation() {
            return state;
        },
        addNestedAggregation(aggregation) {
            // NestedAggregationItem only allows non-nested types, so we cast here
            // The runtime will handle validation
            const nestedItem = aggregation.aggregation;
            const nestedAggregations = [
                ...(state.nested?.nestedAggregations ?? []),
                nestedItem,
            ];
            state = { ...state, nested: { nestedAggregations } };
            return builder;
        },
    };
    return builder;
}
/**
 * Creates an AggregationBuilder for constructing aggregations
 * @param name - The name of the aggregation
 * @returns An AggregationBuilder with chainable methods
 */
function createAggregationBuilder(name) {
    let state = { name };
    const builder = {
        get aggregation() {
            return state;
        },
        ofType(type) {
            state = { ...state, type };
            return builder;
        },
        onField(field) {
            state = { ...state, fieldPath: field };
            return builder;
        },
        asValueAggregation() {
            return createValueAggregationBuilder(state);
        },
        asRangeAggregation() {
            return createRangeAggregationBuilder(state);
        },
        asDateHistogramAggregation() {
            return createDateHistogramAggregationBuilder(state);
        },
        asScalarAggregation() {
            return createScalarAggregationBuilder(state);
        },
        asNestedAggregation() {
            return createNestedAggregationBuilder(state);
        },
    };
    return builder;
}
/**
 * Creates the Aggregation factory
 * @returns An AggregationFactory for creating aggregation expressions
 */
function createAggregationFactory() {
    return (name) => createAggregationBuilder(name);
}
// ============ Search Builder ============
/**
 * Creates the SearchBuilder factory
 * @template T - Entity type
 * @template S - Search spec
 * @template R - Output type from build() (defaults to SearchRequest<T, S>)
 * @returns A factory function that creates SearchBuilder instances
 */
function createSearchBuilderFactory() {
    return () => {
        let state = {};
        const builder = {
            withFilter(filterExpr) {
                state = { ...state, filter: filterExpr.filter };
                return builder;
            },
            withSearchClause(searchExpr) {
                state = { ...state, search: searchExpr.search };
                return builder;
            },
            withSorting(...sorts) {
                state = { ...state, sort: sorts.map((s) => s.sort) };
                return builder;
            },
            withAggregation(...aggregations) {
                state = {
                    ...state,
                    aggregations: aggregations.map((a) => a.aggregation),
                };
                return builder;
            },
            withPaging(paging) {
                state = { ...state, paging };
                return builder;
            },
            withTimeZone(timeZone) {
                state = { ...state, timeZone };
                return builder;
            },
            build() {
                // Cast to R - at runtime it's the same structure,
                // TypeScript uses R for type checking
                return state;
            },
        };
        return builder;
    };
}
// ============ Main Export ============
/**
 * Creates type-safe search helpers for a specific entity and spec.
 * These helpers are static and don't require any context.
 * @template T - Entity type
 * @template S - Search spec defining filterable/sortable/searchable/aggregatable fields
 * @template R - Output type from SearchBuilder.build() (defaults to SearchRequest<T, S>)
 * @returns SearchHelpers containing SearchBuilder, Filter, Sort, Search, and Aggregation
 * @example
 * // Basic usage - build() returns SearchRequest<Product, ProductSearchSpec>
 * const helpers = createSearchUtils<Product, ProductSearchSpec>();
 *
 * // With custom output type - build() returns CustomSearchRequest
 * const helpers = createSearchUtils<Product, ProductSearchSpec, CustomSearchRequest>();
 *
 * // In module definition
 * export const products = {
 *   ...createSearchUtils<Product, ProductSearchSpec>(),
 *   searchProducts: createRESTModule(...),
 * };
 *
 * // Consumer usage
 * import { products } from '@wix/stores';
 *
 * const { SearchBuilder, Filter, Sort, Search, Aggregation } = products;
 *
 * const request = SearchBuilder()
 *   .withFilter(
 *     Filter.and(
 *       Filter('title').eq('Product'),
 *       Filter('price').gt(50)
 *     )
 *   )
 *   .withSearchClause(
 *     SearchParams('dark shoes').fuzzy(true)
 *   )
 *   .withAggregation(
 *     Aggregation('status_count')
 *       .ofType('VALUE')
 *       .onField('status')
 *       .asValueAggregation()
 *       .sortBy('COUNT', 'DESC')
 *       .limit(10)
 *   )
 *   .withSorting(Sort('price').desc())
 *   .withPaging({ limit: 20 })
 *   .build();
 */
export function createSearchUtils() {
    return {
        SearchBuilder: createSearchBuilderFactory(),
        Filter: createFilterFactory(),
        Sort: createSortFactory(),
        SearchParams: createSearchParamsFactory(),
        Aggregation: createAggregationFactory(),
    };
}
